import{_ as e,o as t,c as s,j as r,a as n,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const m=JSON.parse('{"title":"蜘蛛战衣","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/3.防具/7.可升级/蜘蛛战衣.md","filePath":"4.资源分区/7.物品与装备/3.防具/7.可升级/蜘蛛战衣.md"}'),p={name:"4.资源分区/7.物品与装备/3.防具/7.可升级/蜘蛛战衣.md"};function b(d,a,_,l,i,c){return t(),s("div",null,[...a[0]||(a[0]=[r("h1",{id:"蜘蛛战衣",tabindex:"-1"},[n("蜘蛛战衣 "),r("a",{class:"header-anchor",href:"#蜘蛛战衣","aria-label":'Permalink to "蜘蛛战衣"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调018")])])],-1),o('<h1 id="蜘蛛战衣-1" tabindex="-1">蜘蛛战衣 <a class="header-anchor" href="#蜘蛛战衣-1" aria-label="Permalink to &quot;蜘蛛战衣&quot;">​</a></h1><p>蜘蛛战衣<br> 可升级防具<br> 购买和升级时可以指定蜘蛛战衣的服装样式，例如初代蜘蛛侠彼得帕克、小黑蛛迈尔斯莫拉莱斯、幽灵蜘蛛格温史黛西等，如果不指定则默认采用彼得帕克的经典红蓝战衣外形。<br> 战衣效果默认高级取代低级，价格为差价升级。</p><p>D+500<br> 轻甲<br> 盔甲防御6/6<br> 具有【防弹】，提供反射豁免的2DP器械加值。<br> 穿戴者获得等同于基本移动速度的攀爬速度。</p><p>C+1000<br> 盔甲防御10/10<br> 具有【防弹】【防能量武器】，提供反射豁免的2DP器械加值与1个附加成功。<br> 穿戴者获得等同于基本移动速度的攀爬速度，攀爬或利用蛛丝移动时移速+5M，如果已拥有类似能力，敏捷检定+1器械加值。<br> 穿戴者获得4根金属蜘蛛附肢，这不能像手一样使用或持握武器，但是可以辅助进行战斗。展开/收起蜘蛛附肢需要一个迅捷/反射动作，这使你在运动上获得2DP器械加值。</p><p>B+2000<br> 盔甲防御17/17<br> 具有【防弹】【防能量武器】，提供反射豁免的2DP器械加值与1个附加成功。<br> 穿戴者获得等同于基本移动速度的攀爬速度，攀爬或利用蛛丝移动时移速+15M。<br> 穿戴者获得4根金属蜘蛛附肢，这不能像手一样使用或持握武器，但是可以辅助进行战斗。展开/收起蜘蛛附肢需要一个迅捷/反射动作，这使你在运动上获得6DP器械加值和1点附加成功。<br> 在蜘蛛附肢展开时，你每轮都能以自由动作进行一次移动。</p><p>配件：<br> 翼装滑翔<br> 500<br> 战衣的两腋部位加装了蛛网翼装薄膜，可以在空中短距离翼装滑翔，视为免疫自然坠落伤害。</p><hr><p>Copyright ? 2024 TMDtrpg制作组. All Rights Reserved.</p>',8)])])}const P=e(p,[["render",b]]);export{m as __pageData,P as default};
